body.script:
          const GAMES = ["snow-rider-3d","slope","1v1.lol","among-us","fnaf","cookie-clicker","fruit-ninja","subway-surfers","angry-birds","cut-the-rope","fireboy-and-watergirl","bloons-td-5","drift-boss","doodle-jump","2048","bitlife","backrooms","basketball-stars","bad-ice-cream","crossy-road","earn-to-die","flappy-bird","chess","paper.io","rooftop-snipers","volley-random"];
          const emojiMap = {"snow-rider-3d":"🏔️","slope":"⛰️","1v1.lol":"🥅","among-us":"👾","fnaf":"🐻","cookie-clicker":"🍪","fruit-ninja":"🍉","fireboy-and-watergirl":"🔥💧","drift-boss":"🏎️","2048":"🔢","bitlife":"📱","backrooms":"🚪","chess":"♟️","flappy-bird":"🐦"};
          const grid = document.getElementById("gameGrid");
          const currentSpan = document.getElementById("currentGame");
          const statusDiv = document.getElementById("status");
          const reloadBtn = document.getElementById("reloadBtn");

          let currentAlias = "snow-rider-3d";

          function loadGame(alias){
            currentAlias = alias;
            currentSpan.innerText = alias;
            const player = document.getElementById("gamePlayer");
            player.setAttribute("alias", alias);
            player.setAttribute("gid", "session");
            statusDiv.innerHTML = `🎮 ${alias} · starting...`;
            window.nex.session.start();
          }

          function buildGrid(){
            grid.innerHTML = GAMES.map(g => {
              const emoji = emojiMap[g] || "🎮";
              const name = g.replace(/-/g,' ');
              return `
${emoji}${name}`;
            }).join('');
            document.querySelectorAll('.card').forEach(card => {
              card.onclick = () => loadGame(card.getAttribute('data-game'));
            });
          }

          reloadBtn.onclick = () => loadGame(currentAlias);

          window.nex.session.on('progress', (d) => {
            let p = Math.floor(d.progress * 100);
            statusDiv.innerHTML = `📦 ${currentAlias} · ${p}%`;
          });
          window.nex.session.on('ready', () => {
            statusDiv.innerHTML = `✅ ${currentAlias} · ready!`;
            setTimeout(() => { if(window.nex.session) statusDiv.innerHTML = `⚡ ${currentAlias}`; }, 1500);
          });
          window.nex.session.on('error', (e) => {
            statusDiv.innerHTML = `❌ error: ${e.message || 'failed'}`;
          });

          buildGrid();
          loadGame("snow-rider-3d");
